"use client";

import React, { useState, useEffect } from 'react';

export default function SyncAdminPage() {
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<string | null>(null);
    const [sets, setSets] = useState<any[]>([]);
    const [cardCount, setCardCount] = useState<number>(0);
    const [syncProgress, setSyncProgress] = useState<{ current: string, total: number, done: number } | null>(null);

    const fetchStats = async () => {
        try {
            const res = await fetch('/api/admin/sync-cards/stats');
            if (!res.ok) throw new Error(`HTTP ${res.status}`);
            const data = await res.json();
            if (data.count !== undefined) setCardCount(data.count);
        } catch (err) {
            console.error("Erro ao buscar estat├¡sticas:", err);
        }
    };

    useEffect(() => {
        const fetchSets = async () => {
            try {
                const res = await fetch('https://api.tcgdex.net/v2/pt/sets');
                const data = await res.json();
                setSets(data.reverse()); // Novas cole├º├Áes primeiro
            } catch (err) {
                setStatus("Erro ao carregar cole├º├Áes da TCGdex.");
            }
        };
        fetchSets();
        fetchStats();
    }, []);

    const handleSync = async (setId?: string) => {
        setLoading(true);
        setStatus(null);

        try {
            if (setId) {
                setSyncProgress({ current: 'Buscando dados...', total: 1, done: 0 });
                const res = await fetch('/api/admin/sync-cards', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ setId })
                });

                if (!res.ok) {
                    const errorText = await res.text();
                    throw new Error(`Erro no servidor (${res.status}): ${errorText.substring(0, 100)}`);
                }

                const data = await res.json();
                if (data.success) {
                    setStatus(`Sucesso! ${data.count} cards sincronizados.`);
                    await fetchStats();
                } else {
                    throw new Error(data.error);
                }
            } else {
                // Sync last 5
                const last5 = sets.slice(0, 5);
                setSyncProgress({ current: 'Iniciando...', total: last5.length, done: 0 });

                let totalCount = 0;
                for (let i = 0; i < last5.length; i++) {
                    const set = last5[i];
                    setSyncProgress({ current: `Sincronizando: ${set.name}`, total: last5.length, done: i });

                    const res = await fetch('/api/admin/sync-cards', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ setId: set.id })
                    });

                    if (!res.ok) {
                        console.warn(`Set ${set.name} falhou. Pulando...`);
                        continue;
                    }

                    const data = await res.json();
                    if (data.success) totalCount += data.count;
                }
                setStatus(`Conclu├¡do! Total de ${totalCount} cards sincronizados.`);
                await fetchStats();
            }
        } catch (err: any) {
            setStatus(`Erro: ${err.message}`);
        } finally {
            setLoading(false);
            setSyncProgress(null);
        }
    };

    return (
        <div className="max-w-4xl mx-auto p-12 space-y-8 animate-fade-up">
            <div className="flex justify-between items-end border-b border-slate-100 pb-8">
                <div className="space-y-4">
                    <h1 className="text-4xl font-black tracking-tighter text-slate-900 leading-none">
                        Painel de <span className="text-rose-600">Sincroniza├º├úo</span>
                    </h1>
                    <p className="text-slate-400 font-bold text-xs uppercase tracking-widest leading-none">
                        Importa├º├úo de Cat├ílogo Mestre TCGdex (PT-BR)
                    </p>
                </div>
                <div className="bg-slate-900 px-6 py-4 rounded-2xl text-white flex flex-col items-end">
                    <span className="text-[10px] font-black uppercase tracking-[0.2em] text-rose-500 mb-1">Cat├ílogo Local</span>
                    <span className="text-2xl font-black tabular-nums">{cardCount.toLocaleString('pt-BR')} <span className="text-xs text-slate-500 uppercase">Cards</span></span>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-white border border-slate-200 p-8 rounded-3xl space-y-6 shadow-xl shadow-slate-200/50 h-fit">
                    <h2 className="text-xl font-black text-slate-900 tracking-tighter">Sincroniza├º├úo em Lote</h2>
                    <p className="text-slate-500 text-sm font-medium">Sincroniza as 5 cole├º├Áes mais recentes lan├ºadas.</p>

                    <button
                        onClick={() => handleSync()}
                        disabled={loading}
                        className="w-full h-14 bg-rose-600 text-white font-black uppercase tracking-widest text-[11px] rounded-2xl hover:bg-rose-700 transition-all shadow-lg shadow-rose-600/30 disabled:opacity-50"
                    >
                        {loading ? 'Processando...' : 'Sincronizar ├Ültimas 5'}
                    </button>

                    {syncProgress && (
                        <div className="space-y-2 animate-fade-in">
                            <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-400">
                                <span>{syncProgress.current}</span>
                                <span>{syncProgress.done}/{syncProgress.total}</span>
                            </div>
                            <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                                <div
                                    className="h-full bg-rose-600 transition-all duration-500"
                                    style={{ width: `${(syncProgress.done / syncProgress.total) * 100}%` }}
                                />
                            </div>
                        </div>
                    )}

                    {status && (
                        <div className={`p-4 rounded-xl text-[11px] font-bold animate-fade-in ${status.startsWith('Erro') ? 'bg-red-50 text-red-600 border border-red-100' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'}`}>
                            {status}
                        </div>
                    )}
                </div>

                <div className="bg-white border border-slate-200 p-8 rounded-3xl space-y-6 shadow-xl shadow-slate-200/50 h-[500px] flex flex-col">
                    <h2 className="text-xl font-black text-slate-900 tracking-tighter">Sincronizar por Cole├º├úo</h2>
                    <div className="flex-1 overflow-y-auto pr-2 space-y-2">
                        {sets.length === 0 ? (
                            <div className="space-y-2">
                                {[1, 2, 3, 4, 5].map(i => <div key={i} className="h-12 bg-slate-50 animate-pulse rounded-xl" />)}
                            </div>
                        ) : (
                            sets.map(set => (
                                <div key={set.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100 hover:border-rose-300 transition-colors">
                                    <div className="flex items-center gap-3">
                                        <div className="h-8 w-8 bg-white rounded-lg p-1 flex items-center justify-center border border-slate-100">
                                            <img src={`${set.logo}/logo.png`} alt={set.name} className="max-h-full w-auto grayscale" />
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-[11px] font-bold text-slate-700 leading-tight">{set.name}</span>
                                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{set.cards} Cards</span>
                                        </div>
                                    </div>
                                    <button
                                        onClick={() => handleSync(set.id)}
                                        disabled={loading}
                                        className="px-4 py-2 bg-white border border-slate-200 text-[9px] font-black uppercase tracking-widest rounded-lg hover:bg-slate-900 hover:text-white transition-all disabled:opacity-50"
                                    >
                                        Sync
                                    </button>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

import { NextResponse } from 'next/server';
import { supabase, supabaseAdmin } from '@/lib/supabase';

// TCGdex API Base URL
const TCGDEX_API = 'https://api.tcgdex.net/v2/pt';

export async function POST(request: Request) {
    try {
        const { setId } = await request.json();

        if (setId) {
            // Sync specific set
            const result = await syncSet(setId);
            return NextResponse.json(result);
        } else {
            // Sync all sets (Warning: This might be heavy)
            const response = await fetch(`${TCGDEX_API}/sets`);
            const sets = await response.json();

            let totalSynced = 0;
            // For safety and to avoid timeouts, we'll only sync the last 5 sets if no ID is provided
            // or we could implement a more robust background worker.
            const setsToSync = sets.slice(-5);

            for (const set of setsToSync) {
                const result = await syncSet(set.id);
                if (result.success) totalSynced += result.count;
            }

            return NextResponse.json({
                success: true,
                message: `Sincronizados ${totalSynced} cards dos ├║ltimos 5 sets.`,
                setsSynced: setsToSync.map((s: any) => s.name)
            });
        }
    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

async function syncSet(setId: string) {
    try {
        const response = await fetch(`${TCGDEX_API}/sets/${setId}`);
        if (!response.ok) throw new Error(`Set ${setId} n├úo encontrado na TCGdex`);

        const setData = await response.json();
        const cards = setData.cards || [];

        const cardsToInsert = cards.map((card: any) => ({
            id: card.id,
            local_id: card.localId,
            name: card.name,
            image_url: `${card.image}/high.png`,
            set_id: setData.id,
            set_name: setData.name,
            rarity: card.rarity || 'Common',
            updated_at: new Date().toISOString()
        }));

        const { error } = await supabaseAdmin
            .from('pokemon_cards')
            .upsert(cardsToInsert, { onConflict: 'id' });

        if (error) throw error;

        return { success: true, count: cardsToInsert.length };
    } catch (err: any) {
        console.error(`Erro ao sincronizar set ${setId}:`, err);
        return { success: false, error: err.message };
    }
}

import { NextResponse } from 'next/server';
import { supabase, supabaseAdmin } from '@/lib/supabase';

export async function GET() {
    try {
        const { count, error } = await supabaseAdmin
            .from('pokemon_cards')
            .select('*', { count: 'exact', head: true });

        if (error) throw error;

        return NextResponse.json({ success: true, count: count || 0 });
    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

// GET /api/estoque?ids[]=uuid1&ids[]=uuid2
export async function GET(req: Request) {
    try {
        const { searchParams } = new URL(req.url);
        const ids = searchParams.getAll('ids[]');

        if (!ids || ids.length === 0) {
            return NextResponse.json({ error: 'IDs de produto s├úo obrigat├│rios' }, { status: 400 });
        }

        const { data, error } = await supabase
            .from('inventory')
            .select('id, quantity')
            .in('id', ids);

        if (error) throw error;

        // Return map of id -> available quantity
        const stockMap: Record<string, number> = {};
        for (const item of (data || [])) {
            stockMap[item.id] = item.quantity;
        }

        return NextResponse.json(stockMap);
    } catch (error: any) {
        console.error('Erro API estoque:', error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { MercadoPagoConfig, Payment } from 'mercadopago';
import { supabase } from '@/lib/supabase';

// Initialize MP using the generic credentials
const client = new MercadoPagoConfig({ accessToken: process.env.MP_ACCESS_TOKEN || '' });
const payment = new Payment(client);

export async function POST(req: Request) {
    try {
        const body = await req.json();
        const {
            transactionAmount, token, description, installments, paymentMethodId,
            issuerId, payerEmail, userId, useCashback, discountAmount, payer,
            items = [], totalAmount
        } = body;

        if (transactionAmount === undefined) {
            return NextResponse.json({ error: 'Valor da transa├º├úo obrigat├│rio' }, { status: 400 });
        }

        let email = payerEmail || payer?.email;

        // Mercado Pago sandbox: for TEST tokens, the payer email must belong to the test account owner.
        if (process.env.MP_ACCESS_TOKEN?.includes('TEST-')) {
            email = 'gustavolanconi@outlook.com';
        }

        if (!email) {
            return NextResponse.json({ error: 'Email do pagador ├® obrigat├│rio' }, { status: 400 });
        }

        // Deduct cashback if requested
        if (useCashback && discountAmount > 0 && userId) {
            const { data: success, error: deductError } = await supabase.rpc('deduct_cashback', {
                p_user_id: userId,
                p_amount: discountAmount
            });
            if (deductError || !success) {
                return NextResponse.json({ error: 'Erro ao descontar cashback. Saldo insuficiente?' }, { status: 400 });
            }
        }

        // 100% cashback: no MP payment needed
        if (transactionAmount === 0 && useCashback && discountAmount > 0) {
            if (userId) {
                await supabase.from('purchases').insert({
                    user_id: userId,
                    items,
                    total_amount: totalAmount || 0,
                    discount_amount: discountAmount,
                    cashback_earned: 0,
                    payment_method: 'cashback',
                    mp_payment_id: 'cashback-' + Date.now(),
                    status: 'approved'
                });
            }
            return NextResponse.json({ id: 'cashback-' + Date.now(), status: 'approved', status_detail: 'accredited' });
        }

        const paymentRequest = {
            body: {
                transaction_amount: Number(transactionAmount),
                token: token,
                description: description || 'Pgto - TCG Mega Store',
                installments: Number(installments) || 1,
                payment_method_id: paymentMethodId,
                issuer_id: issuerId,
                payer: { email }
            }
        };

        const result = await payment.create(paymentRequest);

        // Post-payment: add cashback + save purchase history
        if (result.id && userId) {
            const cashbackAmount = Number(transactionAmount) * 0.05;

            const { error: rpcError } = await supabase.rpc('add_cashback', {
                p_user_id: userId,
                p_amount: cashbackAmount
            });
            if (rpcError) {
                console.error('Erro ao adicionar cashback:', rpcError);
            } else {
                console.log(`Cashback de R$ ${cashbackAmount.toFixed(2)} adicionado para usu├írio ${userId}`);

                const { error: purchaseError } = await supabase.from('purchases').insert({
                    user_id: userId,
                    items,
                    total_amount: totalAmount || transactionAmount,
                    discount_amount: discountAmount || 0,
                    cashback_earned: cashbackAmount,
                    payment_method: paymentMethodId || 'credit_card',
                    mp_payment_id: String(result.id),
                    status: result.status || 'approved'
                });
                if (purchaseError) {
                    console.error('Erro ao salvar hist├│rico de compra:', purchaseError);
                }

                // ATOMIC STOCK DECREMENT
                const { error: stockError } = await supabase.rpc('purchase_items', {
                    p_items: items.map((i: any) => ({ id: i.id, quantity: i.quantity }))
                });
                if (stockError) {
                    console.error('Erro ao baixar estoque:', stockError);
                    // Note: In a production app, you might want to handle this more gracefully
                    // (e.g., flagging the order for manual review if payment was already processed)
                }
            }
        }

        return NextResponse.json({
            id: result.id,
            status: result.status,
            status_detail: result.status_detail,
        });
    } catch (error: any) {
        console.error('Erro Cart├úo MP:', error);
        return NextResponse.json({ error: error.message || 'Houve um erro no pagamento' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { MercadoPagoConfig, Payment } from 'mercadopago';
import { supabase } from '@/lib/supabase';

// Initialize MP using the generic credentials
const client = new MercadoPagoConfig({ accessToken: process.env.MP_ACCESS_TOKEN || '' });
const payment = new Payment(client);

export async function POST(req: Request) {
    try {
        const body = await req.json();
        const { transactionAmount, description, payerEmail, payerFirstName, payerLastName, docType, docNumber, userId, useCashback, discountAmount } = body;

        if (transactionAmount === undefined || !payerEmail) {
            return NextResponse.json({ error: 'Faltam dados obrigat├│rios' }, { status: 400 });
        }

        if (useCashback && discountAmount > 0 && userId) {
            const { data: success, error: deductError } = await supabase.rpc('deduct_cashback', {
                p_user_id: userId,
                p_amount: discountAmount
            });
            if (deductError || !success) {
                return NextResponse.json({ error: 'Erro ao descontar cashback. Saldo insuficiente?' }, { status: 400 });
            }
        }

        // Se o valor final for 0 (100% pago com cashback), ignorar MP
        if (transactionAmount === 0 && useCashback && discountAmount > 0) {
            return NextResponse.json({
                id: 'cashback-' + Date.now(),
                status: 'approved',
                status_detail: 'accredited',
                qr_code_base64: null,
                ticket_url: null
            });
        }

        const paymentRequest = {
            body: {
                transaction_amount: Number(transactionAmount),
                description: description || 'Pgto PIX - TCG Mega Store',
                payment_method_id: 'pix',
                payer: {
                    email: payerEmail,
                    first_name: payerFirstName,
                    last_name: payerLastName,
                    identification: {
                        type: docType || 'CPF',
                        number: docNumber || '12345678909' // Default/Mock if missing for test
                    }
                }
            }
        };

        const result = await payment.create(paymentRequest);

        // Se o PIX foi gerado e temos um userId, conceder o cashback para demonstra├º├úo
        // Em um ambiente de produ├º├úo real, far├¡amos isso no Webhook quando o PIX fosse pago de verdade.
        if (result.id && userId) {
            const cashbackAmount = Number(transactionAmount) * 0.05;
            const { error: rpcError } = await supabase.rpc('add_cashback', {
                p_user_id: userId,
                p_amount: cashbackAmount
            });

            if (rpcError) {
                console.error('Erro ao adicionar cashback (PIX):', rpcError);
            } else {
                console.log(`Cashback de R$ ${cashbackAmount} adicionado para usu├írio ${userId}`);
            }
        }

        return NextResponse.json({
            id: result.id,
            status: result.status,
            qr_code: result.point_of_interaction?.transaction_data?.qr_code,
            qr_code_base64: result.point_of_interaction?.transaction_data?.qr_code_base64,
            ticket_url: result.point_of_interaction?.transaction_data?.ticket_url
        });
    } catch (error: any) {
        console.error('Erro PIX:', error);
        return NextResponse.json({ error: error.message || 'Houve um erro no pagamento' }, { status: 500 });
    }
}

"use client";

import React, { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useRouter } from 'next/navigation';

export default function LoginPage() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const router = useRouter();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            const { error: signInError } = await supabase.auth.signInWithPassword({
                email,
                password,
            });

            if (signInError) throw signInError;

            router.push('/membro');
        } catch (err: any) {
            console.error(err); // Changed from 'error' to 'err' to match catch block variable
            alert("Acesso negado. Verifique suas credenciais de acesso.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-[85vh] flex items-center justify-center p-6 bg-white animate-fade-up">
            <div className="w-full max-w-md">
                <div className="text-center mb-10 space-y-4">
                    <div className="h-20 w-20 bg-rose-600 rounded-[30px] flex items-center justify-center text-white text-3xl shadow-2xl shadow-rose-500/30 mx-auto mb-8 transform rotate-6">
                        <span>ÔÜí</span>
                    </div>
                    <h1 className="text-4xl font-black tracking-tighter text-slate-900 uppercase">Acesso ├á <span className="text-rose-600">Loja</span></h1>
                    <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.4em]">Protocolo de Autentica├º├úo TCG Mega Store</p>
                </div>

                <div className="bg-white border border-slate-100 p-8 sm:p-12 rounded-[40px] shadow-[0_30px_60px_rgba(0,0,0,0.05)] relative overflow-hidden">
                    <form onSubmit={handleLogin} className="space-y-6 relative z-10">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">E-mail Corporativo</label>
                            <input
                                required
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="exemplo@tcgmegastore.com"
                                className="w-full h-14 px-6 bg-slate-50 border border-transparent rounded-2xl focus:border-rose-600 focus:bg-white focus:ring-4 focus:ring-rose-50 outline-none transition-all font-bold text-sm text-slate-900"
                            />
                        </div>

                        <div className="space-y-2">
                            <div className="flex justify-between items-center ml-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Chave de Acesso</label>
                                <button type="button" className="text-[9px] font-black text-rose-600 uppercase tracking-widest hover:underline">Esqueci</button>
                            </div>
                            <input
                                required
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                                className="w-full h-14 px-6 bg-slate-50 border border-transparent rounded-2xl focus:border-rose-600 focus:bg-white focus:ring-4 focus:ring-rose-50 outline-none transition-all font-bold text-sm text-slate-900"
                            />
                        </div>

                        <button
                            disabled={loading}
                            className="w-full h-16 bg-slate-900 text-white font-black uppercase tracking-[0.2em] text-[11px] rounded-2xl shadow-xl hover:bg-rose-600 transition-all transform hover:-translate-y-1 disabled:opacity-50"
                        >
                            {loading ? 'Validando...' : 'Entrar no Sistema'}
                        </button>
                    </form>

                    <div className="mt-10 text-center border-t border-slate-50 pt-10">
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">
                            Novo colecionador? <a href="/auth/register" className="text-rose-600 hover:text-rose-700 transition-colors">Criar Conta de Cliente</a>
                        </p>
                    </div>
                </div>

                <div className="mt-16 flex items-center justify-center gap-6 opacity-30">
                    <span className="text-[9px] font-black tracking-[0.4em] text-slate-900">ENCRYPT_AES_256</span>
                    <div className="h-1.5 w-1.5 bg-rose-600 rounded-full"></div>
                    <span className="text-[9px] font-black tracking-[0.4em] text-slate-900">POKE_PROTO_v5.0</span>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useRouter } from 'next/navigation';

export default function RegisterPage() {
    const router = useRouter();
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleRegister = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (password !== confirmPassword) {
            setError('As senhas n├úo coincidem.');
            return;
        }
        if (password.length < 8) {
            setError('A senha deve ter no m├¡nimo 8 caracteres.');
