            {/* Stats Summary */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-20">
                {[
                    { label: "VALOR_EM_LOJA_", value: "R$ 428.500", trend: "+12.4%", icon: "­ƒÆ░" },
                    { label: "ITENS_ATIVOS_", value: `${cards.length} Cards`, trend: "+3 este m├¬s", icon: "­ƒâÅ" },
