'use client';

import React, { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

interface PurchaseItem {
    id: string;
    name: string;
    price: number;
    quantity: number;
    imageUrl?: string;
}

interface Purchase {
    id: string;
    created_at: string;
    items: PurchaseItem[];
    total_amount: number;
    discount_amount: number;
    cashback_earned: number;
    payment_method: string;
    mp_payment_id: string;
    status: string;
}

const METHOD_LABELS: Record<string, string> = {
    credit_card: 'Cart├úo de Cr├®dito',
    debit_card: 'Cart├úo de D├®bito',
    pix: 'Pix',
    bank_transfer: 'Transfer├¬ncia',
    cashback: 'Cashback',
};

const STATUS_STYLE: Record<string, string> = {
    approved: 'bg-emerald-50 text-emerald-700 border-emerald-100',
    pending: 'bg-amber-50 text-amber-700 border-amber-100',
    rejected: 'bg-red-50 text-red-700 border-red-100',
};

export default function PedidosPage() {
    const [purchases, setPurchases] = useState<Purchase[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        async function fetchPurchases() {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) { setLoading(false); return; }

            const { data, error } = await supabase
                .from('purchases')
                .select('*')
                .eq('user_id', user.id)
                .order('created_at', { ascending: false });

            if (!error) setPurchases(data || []);
            setLoading(false);
        }
        fetchPurchases();
    }, []);

    const formatDate = (iso: string) =>
        new Intl.DateTimeFormat('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }).format(new Date(iso));

    const formatCurrency = (v: number) =>
        new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

    return (
        <div className="max-w-4xl mx-auto px-6 py-16 min-h-screen">
            <div className="mb-12 space-y-3">
                <span className="inline-block px-3 py-1 rounded-full bg-slate-100 text-slate-500 font-black text-[9px] uppercase tracking-widest border border-slate-200">
                    Minha Conta
                </span>
                <h1 className="text-4xl font-black tracking-tighter text-slate-900">
                    Hist├│rico de <span className="text-rose-600">Pedidos.</span>
                </h1>
                <p className="text-slate-400 text-sm">Todas as suas compras em um s├│ lugar.</p>
            </div>

            {loading ? (
                <div className="text-center py-20 text-slate-400 animate-pulse font-bold text-sm">Carregando...</div>
            ) : purchases.length === 0 ? (
                <div className="text-center py-20 space-y-3">
                    <div className="text-5xl">­ƒøì´©Å</div>
                    <p className="text-slate-400 font-bold text-sm">Nenhuma compra realizada ainda.</p>
                </div>
            ) : (
                <div className="space-y-6">
                    {purchases.map((p) => (
                        <div key={p.id} className="border border-slate-100 rounded-3xl p-6 bg-white shadow-sm space-y-4 hover:shadow-md transition-shadow">
                            {/* Header */}
                            <div className="flex flex-wrap justify-between items-start gap-3">
                                <div className="space-y-1">
                                    <p className="font-black text-slate-900 text-sm">{formatDate(p.created_at)}</p>
                                    <p className="text-slate-400 font-mono text-[11px]">ID: {p.mp_payment_id}</p>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className={`px-3 py-1 rounded-full border text-[10px] font-black uppercase tracking-widest ${STATUS_STYLE[p.status] || STATUS_STYLE.pending}`}>
                                        {p.status === 'approved' ? 'Ô£ô Aprovado' : p.status}
                                    </span>
                                    <span className="text-[10px] text-slate-400 font-bold">
                                        {METHOD_LABELS[p.payment_method] || p.payment_method}
                                    </span>
                                </div>
                            </div>

                            {/* Items */}
                            <div className="divide-y divide-slate-50">
                                {(p.items || []).map((item, idx) => (
                                    <div key={idx} className="flex justify-between items-center py-3 text-sm">
                                        <div className="flex items-center gap-3">
                                            {item.imageUrl && (
                                                <img src={item.imageUrl} alt={item.name} className="w-10 h-10 object-contain rounded-lg border border-slate-100" />
                                            )}
                                            <div>
                                                <p className="font-bold text-slate-800">{item.name}</p>
                                                <p className="text-slate-400 text-xs">Qtd: {item.quantity}</p>
                                            </div>
                                        </div>
                                        <span className="font-black text-slate-900">{formatCurrency(item.price * item.quantity)}</span>
                                    </div>
                                ))}
                            </div>

                            {/* Totals */}
                            <div className="pt-3 border-t border-slate-50 space-y-1">
                                {p.discount_amount > 0 && (
                                    <div className="flex justify-between text-xs text-emerald-600 font-bold">
                                        <span>Cashback utilizado</span>
                                        <span>- {formatCurrency(p.discount_amount)}</span>
                                    </div>
                                )}
                                <div className="flex justify-between font-black text-slate-900 text-base">
                                    <span>Total pago</span>
                                    <span>{formatCurrency(p.total_amount - p.discount_amount)}</span>
                                </div>
                                {p.cashback_earned > 0 && (
                                    <div className="flex justify-between text-xs text-blue-600 font-bold">
                                        <span>Cashback ganho nesta compra</span>
                                        <span>+ {formatCurrency(p.cashback_earned)}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { initMercadoPago, Payment } from '@mercadopago/sdk-react';
import { supabase } from '@/lib/supabase';
import { useCart } from '@/context/CartContext';

// Module-level singleton to prevent double-init in React 18 Strict Mode
let mpInitialized = false;

export default function PagamentoPage() {

    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [user, setUser] = useState<any>(null);
    const [walletBalance, setWalletBalance] = useState<number>(0);
    const [useCashback, setUseCashback] = useState<boolean>(false);
    const [brickKey, setBrickKey] = useState(0); // forces brick remount when amount changes

    const { items, total, clearCart } = useCart();
    const discount = useCashback ? Math.min(walletBalance, total) : 0;
    const finalAmount = Math.max(0, total - discount);

    useEffect(() => {
        // Initialize MP exactly once (guard against React 18 Strict Mode double-invoke)
        if (!mpInitialized) {
            mpInitialized = true;
            initMercadoPago(process.env.NEXT_PUBLIC_MP_PUBLIC_KEY as string, { locale: 'pt-BR' });
        }

        // Fetch logged in user
        supabase.auth.getUser().then(({ data: { user } }) => {
            if (user) {
                setUser({
                    id: user.id,
                    email: user.email,
                    name: user.user_metadata?.name || user.email?.split('@')[0]
                });
            }
        });
    }, []);

    const initialization = {
        amount: finalAmount || 0.10, // Must provide some amount to Brick
    };

    const onSubmit = async ({ selectedPaymentMethod, formData }: any) => {
        setLoading(true);
        console.log("Submit do Brick", formData);

        try {
            // Using the card/general checkout endpoint that handles the tokenized/brick data
            const req = await fetch('/api/pagamento/cartao', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionAmount: formData.transaction_amount || finalAmount,
                    token: formData.token,
                    description: `Compra de cartas - ${items.length} itens`,
                    installments: formData.installments,
                    paymentMethodId: formData.payment_method_id,
                    issuerId: formData.issuer_id,
                    payerEmail: formData.payer?.email || user?.email || 'teste@exemplo.com',
                    payer: formData.payer,
                    userId: user?.id,
                    useCashback: useCashback,
                    discountAmount: discount,
                    totalAmount: total,
                    items: items.map((i: any) => ({ id: i.id, name: i.name, price: i.price, quantity: i.quantity, imageUrl: i.imageUrl }))
                }),
            });
            const res = await req.json();
            if (res.error) throw new Error(res.error);
            alert(`Pedido finalizado com sucesso! (Mercado Pago ID: ${res.id})`);
            clearCart();
            router.push('/');
        } catch (error: any) {
            console.error(error);
            alert('Erro ao processar o pagamento: ' + error.message);
        } finally {
            setLoading(false);
        }
    };

    const onError = async (error: any) => {
        console.error(error);
    };

    const onReady = async () => {
        console.log('MP Brick Ready');
    };

    return (
        <div className="max-w-4xl mx-auto px-6 py-20 min-h-screen animate-fade-up">
            <div className="mb-12 text-center space-y-4">
                <span className="inline-block px-4 py-1.5 rounded-full bg-blue-50 text-blue-600 font-black text-[10px] uppercase tracking-widest border border-blue-100">
                    Checkout Seguro Mercado Pago
                </span>
                <h1 className="text-4xl sm:text-5xl font-black tracking-tighter text-slate-900 leading-none">
                    Finalizar <span className="text-blue-600">Pagamento.</span>
                </h1>
                <p className="text-slate-500 font-medium text-sm">
                    Utilizamos a tecnologia do Mercado Livre / Mercado Pago para todas as op├º├Áes.
                </p>
            </div>

            <div className="bg-white border border-slate-200 p-8 sm:p-12 rounded-[40px] shadow-sm">

                {/* Resumo do Carrinho & Carteira */}
                <div className="mb-10 space-y-4">
                    <h3 className="text-xl font-black text-slate-900 tracking-tighter border-b border-slate-100 pb-2">Resumo do Pedido</h3>

                    <div className="flex justify-between items-center text-sm font-medium text-slate-500">
                        <span>Subtotal ({items.length} itens):</span>
                        <span>R$ {total.toFixed(2).replace('.', ',')}</span>
                    </div>

                    {walletBalance > 0 && (
                        <label className="flex items-center justify-between bg-rose-50 border border-rose-100 p-4 rounded-2xl cursor-pointer">
                            <div className="flex items-center space-x-3">
                                <input
                                    type="checkbox"
                                    checked={useCashback}
                                    onChange={(e) => setUseCashback(e.target.checked)}
                                    className="w-5 h-5 accent-rose-600 cursor-pointer"
                                />
                                <div>
                                    <p className="text-[11px] font-black uppercase tracking-widest text-rose-600">Usar Saldo da Carteira</p>
                                    <p className="text-xs text-rose-700/70 font-medium">Voc├¬ tem R$ {walletBalance.toFixed(2).replace('.', ',')} dispon├¡veis para abater.</p>
                                </div>
                            </div>
                            <span className="font-black text-rose-600">- R$ {discount.toFixed(2).replace('.', ',')}</span>
                        </label>
                    )}

                    <div className="flex justify-between items-end border-t border-slate-100 pt-4 mt-4 !mt-6">
                        <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Total a Pagar</span>
